// IrisAdminServiceServer is the server API for IrisAdminService service.
// All implementations must embed UnimplementedIrisAdminServiceServer
// for forward compatibility.
type IrisAdminServiceServer interface {
	// Listeners (ESMTP) --------------------------------------------------------
	ListListeners(context.Context, *ListListenersRequest) (*ListListenersReply, error)
	CreateListener(context.Context, *CreateListenerRequest) (*Listener, error)
	UpdateListener(context.Context, *UpdateListenerRequest) (*Listener, error)
	// Outbound configuration ---------------------------------------------------
	ListVMTAs(context.Context, *ListVMTAsRequest) (*ListVMTAsReply, error)
	CreateVMTA(context.Context, *CreateVMTARequest) (*VMTA, error)
	UpdateVMTA(context.Context, *UpdateVMTARequest) (*VMTA, error)
	ListVMTAGroups(context.Context, *ListVMTAGroupsRequest) (*ListVMTAGroupsReply, error)
	CreateVMTAGroups(context.Context, *CreateVMTAGroupRequest) (*VMTAGroup, error)
	UpdateVMTAGroup(context.Context, *UpdateVMTAGroupRequest) (*VMTAGroup, error)
	// IP warmup: ramp a VMTA's volume per receiving-domain family over a curve.
	ListWarmupSchedules(context.Context, *ListWarmupSchedulesRequest) (*ListWarmupSchedulesReply, error)
	CreateWarmupSchedule(context.Context, *CreateWarmupScheduleRequest) (*WarmupSchedule, error)
	UpdateWarmupSchedule(context.Context, *UpdateWarmupScheduleRequest) (*WarmupSchedule, error)
	PauseWarmupSchedule(context.Context, *PauseWarmupScheduleRequest) (*WarmupSchedule, error)
	ResumeWarmupSchedule(context.Context, *ResumeWarmupScheduleRequest) (*WarmupSchedule, error)
	// Delivery blueprints: base per-provider shaping rules (fallback for new IPs).
	ListDeliveryBlueprints(context.Context, *ListDeliveryBlueprintsRequest) (*ListDeliveryBlueprintsReply, error)
	CreateDeliveryBlueprint(context.Context, *CreateDeliveryBlueprintRequest) (*DeliveryBlueprint, error)
	UpdateDeliveryBlueprint(context.Context, *UpdateDeliveryBlueprintRequest) (*DeliveryBlueprint, error)
	SetDeliveryBlueprintStatus(context.Context, *SetDeliveryBlueprintStatusRequest) (*DeliveryBlueprint, error)
	SeedDeliveryBlueprints(context.Context, *SeedDeliveryBlueprintsRequest) (*SeedDeliveryBlueprintsReply, error)
	// TSA automation rules (operator-authored reactive back-off).
	ListAutomationRules(context.Context, *ListAutomationRulesRequest) (*ListAutomationRulesReply, error)
	CreateAutomationRule(context.Context, *CreateAutomationRuleRequest) (*AutomationRule, error)
	UpdateAutomationRule(context.Context, *UpdateAutomationRuleRequest) (*AutomationRule, error)
	SetAutomationRuleStatus(context.Context, *SetAutomationRuleStatusRequest) (*AutomationRule, error)
	ListRoutingRules(context.Context, *ListRoutingRulesRequest) (*ListRoutingRulesReply, error)
	CreateRoutingRule(context.Context, *CreateRoutingRuleRequest) (*RoutingRule, error)
	UpdateRoutingRule(context.Context, *UpdateRoutingRuleRequest) (*RoutingRule, error)
	// Mail operations ----------------------------------------------------------
	ListMailRecords(context.Context, *ListMailRecordsRequest) (*ListMailRecordsReply, error)
	ListBounces(context.Context, *ListBouncesRequest) (*ListBouncesReply, error)
	ListFeedbackReports(context.Context, *ListFeedbackReportsRequest) (*ListFeedbackReportsReply, error)
	ListQueues(context.Context, *ListQueuesRequest) (*ListQueuesReply, error)
	RequestQueueAction(context.Context, *RequestQueueActionRequest) (*QueueActionReply, error)
	// Domain & recipient safety ------------------------------------------------
	ListDKIMDomains(context.Context, *ListDKIMDomainsRequest) (*ListDKIMDomainsReply, error)
	CreateDKIMDomain(context.Context, *CreateDKIMDomainRequest) (*DKIMDomain, error)
	UpdateDKIMDomain(context.Context, *UpdateDKIMDomainRequest) (*DKIMDomain, error)
	// Generate a fresh DKIM key pair. Returns the private key (to save on the
	// domain) and the public DNS TXT record to publish; nothing is persisted.
	GenerateDKIMKey(context.Context, *GenerateDKIMKeyRequest) (*GenerateDKIMKeyReply, error)
	ListSuppressions(context.Context, *ListSuppressionsRequest) (*ListSuppressionsReply, error)
	CreateSuppression(context.Context, *CreateSuppressionRequest) (*Suppression, error)
	UpdateSuppression(context.Context, *UpdateSuppressionRequest) (*Suppression, error)
	// Require-TLS policies (outbound delivery must use TLS for these domains) ---
	ListTLSPolicies(context.Context, *ListTLSPoliciesRequest) (*ListTLSPoliciesReply, error)
	CreateTLSPolicy(context.Context, *CreateTLSPolicyRequest) (*TLSPolicy, error)
	DeleteTLSPolicy(context.Context, *DeleteTLSPolicyRequest) (*DeleteTLSPolicyReply, error)
	// Inbound automation -------------------------------------------------------
	// Inbound routes (maildir / forward / webhook) — the unified inbound mail
	// routing model. A webhook route POSTs the raw RFC822 message to an endpoint.
	ListInboundRoutes(context.Context, *ListInboundRoutesRequest) (*ListInboundRoutesReply, error)
	CreateInboundRoute(context.Context, *CreateInboundRouteRequest) (*InboundRoute, error)
	UpdateInboundRoute(context.Context, *UpdateInboundRouteRequest) (*InboundRoute, error)
	DeleteInboundRoute(context.Context, *DeleteInboundRouteRequest) (*DeleteInboundRouteReply, error)
	ListRspamdResults(context.Context, *ListRspamdResultsRequest) (*ListRspamdResultsReply, error)
	// Feedback loops -----------------------------------------------------------
	// Per-domain FBL enrollments: while awaiting approval, inbound feedback mail
	// is forwarded to a human; once approved the domain enables the ARF parser.
	ListFeedbackLoops(context.Context, *ListFeedbackLoopsRequest) (*ListFeedbackLoopsReply, error)
	CreateFeedbackLoop(context.Context, *CreateFeedbackLoopRequest) (*FeedbackLoop, error)
	UpdateFeedbackLoop(context.Context, *UpdateFeedbackLoopRequest) (*FeedbackLoop, error)
	DeleteFeedbackLoop(context.Context, *DeleteFeedbackLoopRequest) (*DeleteFeedbackLoopReply, error)
	// Authentication -----------------------------------------------------------
	// Login exchanges email + password for a session token. It is exempt from the
	// auth middleware (the operation name contains "Login"). When MFA is required
	// the reply carries a partially-authenticated token plus a status indicating
	// the next step (verify an existing enrollment, or enroll first).
	Login(context.Context, *LoginRequest) (*LoginReply, error)
	// VerifyMFA completes a login by validating a TOTP code, upgrading the
	// partially-authenticated session token to a fully-authenticated one.
	VerifyMFA(context.Context, *VerifyMFARequest) (*LoginReply, error)
	// CurrentUser returns the calling user's profile and effective permissions;
	// the SPA calls it on load to restore a session from a stored token.
	CurrentUser(context.Context, *CurrentUserRequest) (*CurrentUserReply, error)
	// ChangePassword updates the calling user's own password.
	ChangePassword(context.Context, *ChangePasswordRequest) (*ChangePasswordReply, error)
	// Logout is a no-op server-side for stateless tokens; provided so clients can
	// signal intent and the action is audited.
	Logout(context.Context, *LogoutRequest) (*LogoutReply, error)
	// Security administration --------------------------------------------------
	ListUsers(context.Context, *ListUsersRequest) (*ListUsersReply, error)
	CreateUser(context.Context, *CreateUserRequest) (*User, error)
	UpdateUser(context.Context, *UpdateUserRequest) (*User, error)
	// ResetUserPassword sets a new password for a user (admin reset). Requires
	// user:write; the new password is strength-validated and bcrypt-hashed.
	ResetUserPassword(context.Context, *ResetUserPasswordRequest) (*ResetUserPasswordReply, error)
	// MFA enrollment for the calling user (TOTP).
	EnrollMFA(context.Context, *EnrollMFARequest) (*EnrollMFAReply, error)
	ConfirmMFA(context.Context, *ConfirmMFARequest) (*ConfirmMFAReply, error)
	DisableMFA(context.Context, *DisableMFARequest) (*DisableMFAReply, error)
	ListAuditEntries(context.Context, *ListAuditEntriesRequest) (*ListAuditEntriesReply, error)
	// KumoMTA service & configuration ------------------------------------------
	RequestServiceControl(context.Context, *RequestServiceControlRequest) (*ServiceControlRequest, error)
	// GenerateKumoConfig renders the current Iris configuration into KumoMTA
	// policy without applying it (a preview/diff).
	GenerateKumoConfig(context.Context, *GenerateKumoConfigRequest) (*KumoConfig, error)
	// ApplyKumoConfig renders the configuration, writes it to KumoMTA, and
	// reloads the service. High-risk: requires confirmation and is audited.
	ApplyKumoConfig(context.Context, *ApplyKumoConfigRequest) (*ApplyKumoConfigReply, error)
	// KumoConfigStatus reports whether the current configuration has drifted from
	// the last applied policy (a regenerate/apply is pending).
	KumoConfigStatus(context.Context, *KumoConfigStatusRequest) (*KumoConfigStatusReply, error)
	// ACME (Let's Encrypt) -------------------------------------------------------
	GetAcmeAccount(context.Context, *GetAcmeAccountRequest) (*AcmeAccount, error)
	SaveAcmeAccount(context.Context, *SaveAcmeAccountRequest) (*AcmeAccount, error)
	ListAcmeCertificates(context.Context, *ListAcmeCertificatesRequest) (*ListAcmeCertificatesReply, error)
	// RequestAcmeCertificate issues (or re-issues) a certificate via HTTP-01.
	// Synchronous: blocks for the ACME handshake.
	RequestAcmeCertificate(context.Context, *RequestAcmeCertificateRequest) (*AcmeCertificate, error)
	DeleteAcmeCertificate(context.Context, *DeleteAcmeCertificateRequest) (*DeleteAcmeCertificateReply, error)
	// ACME DNS-01 challenge provider configuration.
	ListAcmeDnsProviders(context.Context, *ListAcmeDnsProvidersRequest) (*ListAcmeDnsProvidersReply, error)
	GetAcmeDnsProvider(context.Context, *GetAcmeDnsProviderRequest) (*AcmeDnsProvider, error)
	SetAcmeDnsProvider(context.Context, *SetAcmeDnsProviderRequest) (*AcmeDnsProvider, error)
	ClearAcmeDnsProvider(context.Context, *ClearAcmeDnsProviderRequest) (*AcmeDnsProvider, error)
	GetDashboardSummary(context.Context, *GetDashboardSummaryRequest) (*DashboardSummary, error)
	// GetMetricsTimeseries returns curated mail-flow time-series (deliveries,
	// bounces, deferrals, receptions) from the configured Prometheus.
	GetMetricsTimeseries(context.Context, *GetMetricsTimeseriesRequest) (*MetricsTimeseries, error)
	// GetWarmupDeliveryStats returns per-VMTA, per-recipient-domain delivery and
	// bounce rates over a lookback window — used to watch IP-warmup health.
	GetWarmupDeliveryStats(context.Context, *GetWarmupDeliveryStatsRequest) (*WarmupDeliveryStats, error)
	// GetMailClassStats returns mail volume grouped by mailclass over a lookback
	// window — powers the dashboard "mail by class" panel.
	GetMailClassStats(context.Context, *GetMailClassStatsRequest) (*MailClassStats, error)
	// GetRecipientDomainStats returns the busiest recipient domains by mail volume
	// over a lookback window — powers the dashboard "top recipient domains" panel.
	GetRecipientDomainStats(context.Context, *GetRecipientDomainStatsRequest) (*RecipientDomainStats, error)
	// CheckDomainBounceSetup verifies a domain's MX (accepts bounces here), SPF
	// (authorizes our egress IPs), and DKIM (selector records) via live DNS.
	CheckDomainBounceSetup(context.Context, *CheckDomainBounceSetupRequest) (*DomainBounceCheck, error)
	// Tools ---------------------------------------------------------------------
	// Diagnose reports how mail from a given address is handled and whether the
	// sending domain is set up correctly (DKIM/SPF/DMARC/MX/FBL + routing preview).
	Diagnose(context.Context, *DiagnoseRequest) (*DiagnoseResult, error)
	// RblCheck tests the deployment's listener and VMTA egress IPs against DNS
	// blocklists.
	RblCheck(context.Context, *RblCheckRequest) (*RblCheckReply, error)
	// DMARC aggregate reports -----------------------------------------------------
	GetDmarcStats(context.Context, *GetDmarcStatsRequest) (*DmarcStats, error)
	ListDmarcReports(context.Context, *ListDmarcReportsRequest) (*ListDmarcReportsReply, error)
	ListDmarcDomains(context.Context, *ListDmarcDomainsRequest) (*ListDmarcDomainsReply, error)
	// Generic worker error log: Warn/Error events emitted by background workers
	// (e.g. an unparseable DMARC report dropped by the dmarc worker).
	ListWorkerErrorLogs(context.Context, *ListWorkerErrorLogsRequest) (*ListWorkerErrorLogsReply, error)
	// Retention: per-table TimescaleDB chunk compression/dropping for the event
	// hypertables, with live disk stats.
	ListRetentionPolicies(context.Context, *ListRetentionPoliciesRequest) (*ListRetentionPoliciesReply, error)
	UpdateRetentionPolicy(context.Context, *UpdateRetentionPolicyRequest) (*RetentionPolicy, error)
	RunRetention(context.Context, *RunRetentionRequest) (*RunRetentionReply, error)
	// Global settings (deployment-level policy knobs editable in the UI).
	GetGlobalSettings(context.Context, *GetGlobalSettingsRequest) (*GlobalSettings, error)
	UpdateGlobalSettings(context.Context, *UpdateGlobalSettingsRequest) (*GlobalSettings, error)
	// Subject classifications (rules for the optional subject-classification
	// feature; operator-authored plus AI-generated cache).
	ListSubjectClassifications(context.Context, *ListSubjectClassificationsRequest) (*ListSubjectClassificationsReply, error)
	CreateSubjectClassification(context.Context, *CreateSubjectClassificationRequest) (*SubjectClassification, error)
	UpdateSubjectClassification(context.Context, *UpdateSubjectClassificationRequest) (*SubjectClassification, error)
	DeleteSubjectClassification(context.Context, *DeleteSubjectClassificationRequest) (*DeleteSubjectClassificationReply, error)
	mustEmbedUnimplementedIrisAdminServiceServer()
}

